body.page-Europa_Universalis_4_Wiki h1.firstHeading{display:none}.eu4box{border:2px solid #20303B;background:#3c5a6e}.eu4box .heading{background:#20303B}.eu4box-inline{border:2px solid #92A4B6;background:#FDFDFD !important}.eu4box-inline .heading{background:#6D98B9}.gridBG{background:#3c5a6e url(/images/d/dc/MainBG.jpg) repeat left center}.gridBG2{background:#3c5a6e url(/images/0/07/MainBG2.png) repeat left center}.battlefield{position:relative;width:439px}.battle-terrain{margin:0px auto 0px;text-align:center;position:relative}.battle-terrain .terrain-frame{display:block;position:relative;z-index:999}.battle-terrain .terrain-image{display:block;position:relative;margin-top:-90px}.battle-terrain .location-name{color:white;font-size:13pt;font-weight:bold;text-transform:capitalize;text-shadow:1px 1px 4px black;position:relative;z-index:999;margin-top:-47px;margin-bottom:50px;opacity:0.8}.battle-single{height:30px;overflow:hidden}.battle-single > a{display:block !important;margin-top:-10px !important}.battle-single .battle-team{top:0px !important}.battle-background{position:relative}.battle-team{width:400px;position:absolute;top:10px;left:20px}.battle-team:last-child{margin-top:65px}.battle-team-row{height:10px;text-align:center}.battle-team-row + .battle-team-row{margin-top:3px}.battle-counter{display:inline-block;height:10px !important;width:10px !important}.battle-counter a{position:absolute;opacity:0.6;padding:0px;margin:-6px 0px;display:block;height:10px !important;width:10px !important}.battle-counter-NUL{background:none !important}.battle-counter-NUL img{display:none}.tooltip,.tooltip2,.tooltip3{display:inline-block;border-bottom:1px dotted;position:relative}.tooltip .tooltiptext,.tooltip2 .tooltiptext2,.tooltip3 .tooltiptext3{display:none;width:auto;height:auto;box-shadow:0 0 10px 2px #4e4e4e;border:none;position:absolute;z-index:1;top:50%;left:25px;opacity:0;transition:opacity 0.3s}.tooltip:hover .tooltiptext,.tooltip2:hover .tooltiptext2,.tooltip3:hover .tooltiptext3{display:inline-block;opacity:1}